// Parse & validate RDV data
var data = $input.first().json;
var body = data.body || data;

function safe(s) { return String(s || '').replace(/'/g, "''").substring(0, 500); }
function safeUuid(s) { return String(s || '').replace(/[^a-f0-9-]/gi, '').substring(0, 36); }

var tenantId = safeUuid(body.tenantId);
var nom = safe(body.nom || '');
var prenom = safe(body.prenom || '');
var email = safe(body.email || '');
var telephone = safe(body.telephone || '');
var objet = safe(body.objet || body.notes || 'Rendez-vous');
var dateRdv = safe(body.date || '');
var heureRdv = safe(body.heure || '');
var typeEntretien = safe(body.type || 'telephonique');

if (!tenantId) {
  return [{ json: { error: true, message: 'tenantId requis' }}];
}

// Build date_entretien
var dateEntretien = null;
if (dateRdv && /^\d{4}-\d{2}-\d{2}$/.test(dateRdv)) {
  var time = (heureRdv && /^\d{2}:\d{2}$/.test(heureRdv)) ? heureRdv : '09:00';
  dateEntretien = dateRdv + ' ' + time + ':00';
}

return [{ json: {
  error: false,
  tenantId, nom, prenom, email, telephone, objet, dateEntretien, typeEntretien
}}];

parameters.query:
={{ (function() {
  var d = $input.first().json;
  var sql = "INSERT INTO leads (id, tenant_id, nom, prenom, email, telephone, source, statut, notes";
  var vals = "VALUES (gen_random_uuid(), '" + d.tenantId + "', '" + d.nom + "', '" + d.prenom + "', '" + d.email + "', '" + d.telephone + "', 'telephone_rdv', 'nouveau', 'RDV: " + d.objet + "'";

  if (d.dateEntretien) {
    sql += ", date_entretien, type_entretien";
    vals += ", '" + d.dateEntretien + "', '" + d.typeEntretien + "'";
  }

  sql += ", created_at, updated_at) ";
  vals += ", NOW(), NOW())";

  return sql + " " + vals + " RETURNING id, nom, prenom, telephone, date_entretien, type_entretien";
})() }}

parameters.responseBody:
={{ (function() {
  var row = $input.first().json;
  return JSON.stringify({
    success: true,
    message: 'Rendez-vous créé avec succès',
    rdv: {
      id: row.id || '',
      nom: row.nom || '',
      prenom: row.prenom || '',
      telephone: row.telephone || '',
      date_entretien: row.date_entretien || null,
      type_entretien: row.type_entretien || 'telephonique'
    }
  });
})() }}
